<template>
  <div class="bgImg">
    <div class="quoteDiv">
      <transition
        name="slide-fade"
        mode="out-in"
      >
        <span class="quoteText">
          Software Developer. Data Engineer.
        </span>
      </transition>
    </div>
  </div>
</template>

<script>
export default {
  name: 'Home',
  data: function () {
    return {
      msg: 'Isaac Phua\'s home page'
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1,
h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
.quoteDiv {
  position: absolute;
  left: 0px;
  top: 50%;
  width: 100%;
  text-align: center;
}
.quoteText {
  color: white;
  padding-right: 12px;
  padding-left: 12px;
  font-weight: bold;
  font-size: 4em;
}
.bgImg {
    background-image: url('./../assets/img/background.jpg');
    height: 100%;
    width: 100%;

    /* Center and scale the image nicely */
    background-position: center;
    background-repeat: no-repeat;
    background-size: cover;
}
</style>



