<template>
  <div class="outerDiv">
    <div class="sectionTitle"><span>About me</span></div>
    <div class="aboutDiv">
      <v-layout justify-center z-index="0">
        <v-flex xs6 sm4 md3 lg2 my-4>
          <img src="../assets/img/logo.jpg" class="logo" />
        </v-flex>
      </v-layout>
      <v-layout justify-center>
        <v-flex xs12 sm6 md6 lg6 my-4>
          <div class="aboutText">
            {{ about }}
          </div>
        </v-flex>
      </v-layout>
    </div>

    <div class="sectionTitle"><span>Projects</span></div>

    <div class="projectsDiv">
      <v-container
        fluid
        grid-list-md
      >
        <v-layout
          justify-center
          row
          wrap>
          <v-flex
            v-for="item in projects"
            :key="item.title"
            xs12
            sm6
            md6
            lg2
            mx-4
            my-4>
            <v-card flat height="100%">
              <v-img v-bind:src="item.icon" contain height="50%"/>
              <v-card-title primary-title class="cardTitle">
                  {{ item.title }}
              </v-card-title>

              <v-card-text v-show="item.show">
                {{ item.desc }}
              </v-card-text>

              <v-card-actions>
                <v-btn
                  flat
                  color="#EC407A"
                  v-for="(link, index) in item.links"
                  :key="link"
                  :href="link">
                  Link {{ index + 1 }}
                </v-btn>

                <v-spacer />

                <v-btn icon @click="item.show = !item.show">
                  <v-icon>{{ item.show ? 'keyboard_arrow_down' : 'keyboard_arrow_up' }}</v-icon>
                </v-btn>
              </v-card-actions>

            </v-card>
          </v-flex>
        </v-layout>
      </v-container>
    </div>
  </div>
</template>

<script>
export default {
  name: 'about',
  data: function () {
    return {
      projects: [
        {
          title: 'MSSQL Wrapper',
          desc: 'Wrapper library for writing SQL queries in C#',
          links: ['https://github.com/Isaaafc/mssql-wrapper'],
          icon: require('../assets/img/mssql-wrapper.png'),
          show: false
        },
        {
          title: 'Distributed estimation via paid crowd work',
          desc: 'Accepted ICASSP 2016 research paper about collective intelligence',
          links: ['https://ieeexplore.ieee.org/document/7472869'],
          icon: require('../assets/img/icassp.jpg'),
          show: false
        },
        {
          title: 'PTAM on Android',
          desc: 'Porting the PTAM Augmented Reality algorithm to Android 4.x as my final year project in university',
          links: ['https://www.youtube.com/watch?v=2CCHMkcn3Dg', 'https://www.youtube.com/watch?v=HRC4DGti57s'],
          icon: require('../assets/img/ptam.jpg'),
          show: false
        },
        {
          title: 'Django songs database',
          desc: 'Songs database written in Django as a learning project deployable to Heroku',
          links: ['https://www.youtube.com/watch?v=2CCHMkcn3Dg'],
          icon: require('../assets/img/songsdb.jpg'),
          show: false
        }
      ],
      about: 'I am a software engineer currently working in the data science field, performing data engineering tasks in a data analytics firm. My main interests are in data science and machine learning. I have experiences in various frameworks, but now my main tools are C#.NET and Python.'
    }
  }
}
</script>

<!-- styling for the component -->
<style>
.outerDiv {
  position: absolute;
  width: 100%;
}
.aboutDiv {
  padding-top: 50px;
  padding-bottom: 100px;
  width: 80%;
  margin: auto;
  text-align: center;
}
.aboutText {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  color: #2c3e50;
  word-wrap: break-word;
  text-align: justify;
  width: 100%;
}
.projectsDiv {
  width: 100%;
  margin: auto;
}
.sectionTitle {
  -webkit-font-smoothing: antialiased;
  font-weight: bold;
  color: black;
  font-size: 2.5em;
  width: 100%;
  text-align: left;
  padding-left: 5%;
}
.logo {
  width: 100%;
}
.cardTitle {
  font-weight: bold;
}
hr {
  border-color: #EC407A;
}
</style>



